Test pins fail-closed contract. Three cases catch the diff:

1. Forged X-Gateway-User-Id with bad signature must raise Unauthorized, not return User.
2. Legacy X-User-Id alone must raise Unauthorized.
3. No credentials at all must raise Unauthorized, not return None.

Each asserts exception, not return value — "return None" is exactly what current code does, so asserting return shape would pass the bug.

```python
import pytest
from app.middleware.auth import AuthMiddleware, Unauthorized


@pytest.fixture
def mw():
    m = AuthMiddleware()
    m.sessions = {"valid-sid": User(id="u1")}
    m._hmac_key = b"test-key"
    return m


def make_request(headers=None, cookies=None):
    return Request(headers=headers or {}, cookies=cookies or {})


def test_forged_gateway_header_without_valid_signature_rejected(mw):
    req = make_request(headers={
        "X-Gateway-User-Id": "admin",
        "X-Gateway-Signature": "deadbeef",
    })
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)


def test_gateway_header_without_signature_rejected(mw):
    req = make_request(headers={"X-Gateway-User-Id": "admin"})
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)


def test_legacy_x_user_id_header_rejected(mw):
    req = make_request(headers={"X-User-Id": "admin"})
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)


def test_no_credentials_raises_not_returns_none(mw):
    req = make_request()
    with pytest.raises(Unauthorized):
        mw.resolve_user(req)


def test_valid_signature_accepted(mw):
    uid = "u1"
    sig = hmac_sign(mw._hmac_key, uid)
    req = make_request(headers={
        "X-Gateway-User-Id": uid,
        "X-Gateway-Signature": sig,
    })
    assert mw.resolve_user(req).id == "u1"
```

Last case anchors positive path — without it test suite passes by making resolve_user always raise. Five cases together pin shape: valid sig works, everything else raises.
